#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

using namespace std;

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    long long count = 0;

    // Iterate over all possible start indices i
    for (int i = 0; i < n; ++i) {
        // current_or stores the bitwise OR of the subarray nums[i...j]
        long long current_or = 0;

        // A set to store the unique elements encountered so far in nums[i...j]
        // Since we are only interested in whether current_or is present in nums[i...j],
        // and current_or is the OR of all elements, if current_or is present, it must be one of the elements.
        // However, a more direct check is to see if current_or equals any element in nums[i...j].
        // Since the OR operation is monotonic (current_or never decreases), and the number of distinct OR values
        // starting at a fixed i is at most log(max(nums)), we can optimize.

        // A simpler approach for correctness first: O(N^2)
        for (int j = i; j < n; ++j) {
            // Update the bitwise OR for subarray nums[i...j]
            current_or |= nums[j];

            // Check if current_or is present in nums[i...j]
            // We need to check if there exists k such that i <= k <= j and nums[k] == current_or.

            bool present = false;
            for (int k = i; k <= j; ++k) {
                if (nums[k] == current_or) {
                    present = true;
                    break;
                }
            }

            if (present) {
                count++;
            }
        }
    }

    // The O(N^2) approach might TLE given N=10^5. Let's re-evaluate the condition.
    // Condition: OR(nums[i..j]) == nums[k] for some i <= k <= j.

    // Since OR(nums[i..j]) is the OR of all elements, if this value equals some element nums[k],
    // it means that nums[k] must "cover" all the bits set in the OR. 
    // This implies that for every bit set in OR(nums[i..j]), that bit must be set in nums[k].
    // Since nums[k] is one of the elements whose bits contribute to the OR, this is always true 
    // IF the set of elements {nums[i], ..., nums[j]} contains an element equal to the OR.

    // If OR(S) = X, and X is in S, then for every element s in S, s | X = X.
    // This means every element s in S must be a submask of X (s | X = X).
    // This is always true because X = OR(S), so s <= X bitwise.
    // The condition simplifies to: is the OR of the subarray equal to one of its elements?

    // Given N <= 10^5, an O(N log N) or O(N * log(MaxVal)) solution is required.

    // Optimization using the property of OR prefix/suffix sums:
    // For a fixed starting point i, as j increases, the set of distinct values for OR(nums[i..j]) is small (<= 32).

    count = 0;
    for (int i = 0; i < n; ++i) {
        // `or_segments` stores pairs: {OR_value, last_index_where_this_OR_was_achieved_starting_from_i}
        // Wait, this is complex. Let's use the property that for a fixed i, there are few distinct OR values as j increases.

        // current_ors maps: OR_value -> index_j_where_this_OR_first_appeared_for_this_i
        // We only need to track the distinct OR values and where they occur.

        // Instead of tracking the full OR history, let's use a structure that tracks all possible OR values ending at j.
    }

    // Let's switch to the standard fixed-end-point approach (j is fixed, look for valid i)
    // For a fixed ending index j, we want to count i <= j such that OR(nums[i..j]) is in {nums[i], ..., nums[j]}.

    long long total_good_subarrays = 0;

    // For fixed j, track all distinct OR values of subarrays ending at j: OR(nums[i..j]) for i=1..j
    // map: OR_value -> smallest starting index i that yields this OR_value ending at j
    // This is still hard because the required element nums[k] depends on i.

    // Reverting to the O(N^2) structure and optimizing the inner loop check.
    // For a fixed i, as j increases, current_or grows. We only need to check if current_or appears in nums[i..j].

    // We can maintain a frequency map/set for nums[i..j] efficiently, but since j moves, it's still O(N^2).

    // Since N=10^5, O(N^2) is 10^10, definitely TLE. The key must be the property of OR values.

    // Let's use the structure that there are O(log MaxVal) distinct OR values ending at any point j.

    // dp[j] will store a map: {OR_value -> smallest_start_index_i} for all subarrays ending at j.
    // We only need to know which OR values are present in nums[i..j].

    // `ors_ending_at_j` will be a set of pairs: {OR_value, start_index_i} for all distinct ORs ending at j.
    // Since there are O(log V) distinct ORs ending at j, we can iterate over them.

    vector<pair<long long, int>> current_or_states; // {OR_value, start_index_i} for subarrays ending at j-1

    for (int j = 0; j < n; ++j) {
        vector<pair<long long, int>> next_or_states;

        // 1. Subarray [j...j]:
        long long val_j = nums[j];

        // Check [j]: OR = nums[j]. Is nums[j] present? Yes.
        total_good_subarrays++;

        // New state: {nums[j], j}
        next_or_states.push_back({val_j, j});

        // 2. Extend previous subarrays ending at j-1
        for (const auto& state : current_or_states) {
            long long prev_or = state.first;
            int start_i = state.second;

            long long new_or = prev_or | val_j;

            // Add the new state {new_or, start_i}
            next_or_states.push_back({new_or, start_i});
        }

        // Prune next_or_states: Keep only the unique OR values, preferring smaller start indices for the same OR.
        // We use a map to consolidate: OR_value -> min_start_index
        map<long long, int> consolidated_states;
        for (const auto& state : next_or_states) {
            long long or_val = state.first;
            int start_i = state.second;

            if (consolidated_states.find(or_val) == consolidated_states.end() || start_i < consolidated_states[or_val]) {
                consolidated_states[or_val] = start_i;
            }
        }

        current_or_states.clear();
        for(const auto& pair : consolidated_states) {
            current_or_states.push_back(pair);
        }

        // 3. Count good subarrays ending at j using the consolidated states
        // A state {OR_value, start_i} corresponds to the subarray nums[start_i...j].
        // We need to check if OR_value is present in nums[start_i...j].

        // This check is the killer: checking presence in a dynamic range [start_i, j] is slow if done naively.

        // Let's reformulate the condition check for a fixed OR_value = X derived from [i..j].
        // Condition: X must be one of {nums[i], ..., nums[j]}.

        // Since X is the OR of all elements, if X appears in the subarray, the condition is met.

        // If we iterate over the consolidated states {X, i}:
        // We check if X exists in nums[i...j].

        // Since we have O(log V) states, if checking presence takes O(j-i+1), we are back to O(N^2).

        // We need a faster way to check presence.
        // For a fixed X, we need to know if there is an occurrence of X in the range [i, j].
        // We can precalculate the next/previous occurrence of every value.

        // Precomputation:
        // last_occurrence[value] = index of last occurrence of 'value'.
        // next_occurrence[index] = index of next occurrence of nums[index].

        // Let's use precalculated indices for each value.
        vector<vector<int>> indices(1000000001); // Too large for 10^9 values

        // Use map<long long, vector<int>> to store indices for each value.
        map<long long, vector<int>> value_indices;
        for(int k=0; k<n; ++k) {
            value_indices[nums[k]].push_back(k);
        }

        // Now, for a state {X, i} at index j:
        // Is X present in [i, j]?
        // Look up indices of X: `idx_list = value_indices[X]`.
        // Check if there is any index `k` in `idx_list` such that `i <= k <= j`.

        for (const auto& state : consolidated_states) {
            long long X = state.first;
            int i = state.second;

            if (value_indices.count(X)) {
                const auto& idx_list = value_indices[X];

                // Use binary search (lower_bound) on idx_list to find the first index >= i.
                auto it = lower_bound(idx_list.begin(), idx_list.end(), i);

                // If such an index exists AND it is <= j, then X is present.
                if (it != idx_list.end() && *it <= j) {
                    total_good_subarrays++;
                }
            }
        }
    }

    return total_good_subarrays;
}
