#include <vector>
#include <numeric>
#include <algorithm>
#include <set>
#include <map>

/**
 * Definition for a subarray.
 * struct Subarray {
 *     int start;
 *     int end;
 * };
 */

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    long long count = 0;

    // A subarray nums[i...j] is "good" if:
    // (nums[i] | nums[i+1] | ... | nums[j]) == (nums[i] | ... | nums[j]) AND
    // there exists some k in [i, j] such that (nums[i] | ... | nums[j]) == nums[k]

    // Let OR_val = nums[i] | ... | nums[j].
    // The condition is: OR_val is present in {nums[i], ..., nums[j]}.
    // Since OR_val is the bitwise OR of all elements, it must be true that
    // OR_val >= nums[k] for all k in [i, j].
    // If OR_val is present in the subarray, say OR_val = nums[k], then
    // for all j in [i, j], the OR operation must have resulted in nums[k].
    // This means that every bit set in any nums[l] (i <= l <= j) must also be set in nums[k].
    // In other words, nums[k] must be a "superset" (in terms of bits) of every other element in the subarray.
    // nums[l] | nums[k] = nums[k] for all l in [i, j].

    // A simpler way to check the condition:
    // Let OR_val = nums[i] | ... | nums[j].
    // The condition is met if and only if there exists an element nums[k] in the subarray
    // such that nums[k] = OR_val.

    // We iterate over all possible starting points i and extend the subarray to j.
    for (int i = 0; i < n; ++i) {
        long long current_or = 0;
        // Keep track of the elements present in the subarray nums[i...j] for quick checking
        std::set<long long> present_elements;

        for (int j = i; j < n; ++j) {
            // Update OR value
            current_or |= nums[j];

            // Add current element to the set of present elements
            present_elements.insert(nums[j]);

            // Check the condition: Is current_or present in present_elements?
            if (present_elements.count(current_or)) {
                count++;
            }
        }
    }

    return count;
}
