#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

using namespace std;

class Solution {
public:
    long long solve(std::vector<long long> nums) {
        int n = nums.size();
        long long good_subarray_count = 0;

        // A subarray nums[i..j] is "good" if (nums[i] | ... | nums[j]) == (nums[i] | ... | nums[j])
        // AND this value is present in {nums[i], ..., nums[j]}.
        //
        // Let OR_val = nums[i] | ... | nums[j].
        // The condition is: OR_val == x for some x in {nums[i], ..., nums[j]}.
        //
        // This is equivalent to: OR_val must be equal to at least one element in the subarray.
        // Since OR_val is the OR of all elements, it must be greater than or equal to any element in the subarray.
        // If OR_val == x, then for all y in {nums[i], ..., nums[j]}, x | y = x.
        // This means x must be a "superset" (in terms of set bits) of every element in the subarray.
        // Since x itself is one of the elements, this is a strong condition.

        // We iterate over all possible right endpoints j.
        // For a fixed j, we count how many starting points i <= j result in a "good" subarray nums[i..j].

        for (int j = 0; j < n; ++j) {
            // `or_map` stores for each unique OR value achievable by subarrays ending at j,
            // the rightmost starting index i such that nums[i..j] has that OR value.
            // More precisely, it stores {OR_value: starting_index} for the distinct OR values.
            // Since OR values only change when a new bit is set, there are at most log(max(nums[i])) distinct values.

            // prev_or_map stores {OR_value: starting_index} for subarrays ending at j-1.
            // For j=0, this is empty.
            map<long long, int> prev_or_map;

            // current_or_map will store {OR_value: starting_index} for subarrays ending at j.
            map<long long, int> current_or_map;

            // Case 1: Subarray [j..j]. OR = nums[j]. This is always good.
            current_or_map[nums[j]] = j;

            // Iterate over entries from j-1 to find extensions.
            if (j > 0) {
                // 1. Extend all subarrays ending at j-1.
                for (auto const& [or_val, start_idx] : prev_or_map) {
                    long long new_or = or_val | nums[j];

                    // We only need to store the leftmost/earliest starting index for a given OR value 
                    // to simplify logic, but since we are iterating j outwards, 
                    // we just need to ensure we capture all distinct OR values.
                    // If new_or is already in current_or_map, we keep the existing (smaller) starting index.
                    if (current_or_map.find(new_or) == current_or_map.end()) {
                        current_or_map[new_or] = start_idx;
                    }
                }
            }

            // 2. Check the condition for all subarrays ending at j (stored in current_or_map).
            for (auto const& [or_val, start_idx] : current_or_map) {
                // The subarray is nums[start_idx .. j].

                // Condition: or_val must be present in {nums[start_idx], ..., nums[j]}.
                // This means there must exist an element x in nums[start_idx .. j] such that x = or_val.

                bool found = false;

                // Since or_val is the OR of the subarray, if or_val is present, it must be 
                // equal to one of the elements.
                // The most straightforward way to check this is to iterate the subarray, 
                // but O(N^2 log A) will TLE. We need a faster check.

