        for (int j = 0; j < n; ++j) {
            map<long long, int> next_segments;

            // 1. Extend previous segments (from j-1)
            for (auto const& [v, i_start] : segments) {
                long long new_v = v | nums[j];
                // The new segment starts at the same position i_start
                if (next_segments.find(new_v) == next_segments.end() || i_start < next_segments[new_v]) {
                    next_segments[new_v] = i_start;
                }
            }

            // 2. New segment starting at j
            long long self_v = nums[j];
            if (next_segments.find(self_v) == next_segments.end() || j < next_segments[self_v]) {
                next_segments[self_v] = j;
            }

            segments = next_segments;

            // 3. Count good subarrays ending at j
            long long current_j_count = 0;

            // We need to iterate through the segments in decreasing order of start_index (i.e., increasing order of OR value if the OR values are well-behaved, but better to iterate by start index).

            // Collect segments into a vector to easily determine range boundaries.
            vector<pair<long long, int>> sorted_segments;
            for(auto const& [v, i_start] : segments) {
                sorted_segments.push_back({v, i_start});
            }
            // Sort by start index ascending.
            sort(sorted_segments.begin(), sorted_segments.end(), [](const auto& a, const auto& b) {
                return a.second < b.second;
            });

            // Calculate range boundaries (i_start to i_end)
            int prev_i_start = -1;
            for (size_t k = 0; k < sorted_segments.size(); ++k) {
                long long or_val = sorted_segments[k].first;
                int i_start = sorted_segments[k].second;

                // The range for this OR_val is [i_start, i_end]
                // i_end is min(j, next_segment_start - 1)
                int i_end = (k + 1 < sorted_segments.size() ? sorted_segments[k+1].second - 1 : j);

                // Check condition: Does or_val appear in nums[i_start .. j]?
                // Since the OR is or_val, we just need to check if or_val appears at all in nums[i_start .. j].
                // The last occurrence of or_val up to j is last_pos_global[or_val].

                // If last_pos_global[or_val] >= i_start, then or_val is present in [i_start, j].
                // However, we need it to be present in [i..j] for *every* i in the segment [i_start, i_end].
                // Wait, the condition must hold for the specific subarray nums[i..j].

                // If or_val is present at k >= i_start, then for all i <= k, the subarray [i..j] contains or_val.
                // Thus, the condition holds for all i in [i_start, min(i_end, last_pos_global[or_val])].

                if (last_pos_global.count(or_val)) {
                    int last_k = last_pos_global.at(or_val);

                    // The valid starting indices i for this OR_val are in [i_start, i_end] AND i <= last_k.
                    int effective_i_end = min(i_end, last_k);

                    if (effective_i_end >= i_start) {
                        // Number of good subarrays in this segment: effective_i_end - i_start + 1
                        current_j_count += (effective_i_end - i_start + 1);
                    }
                }
            }

            count += current_j_count;

            // Update global last positions for the next iteration j+1
            last_pos_global[nums[j]] = j;
        }

        return count;
    }
};
