using namespace std;

/**
 * @brief 解决“好子数组”计数问题
 * 
 * 一个子数组是“好”子数组，当且仅当该子数组中所有元素的按位或等于该子数组中至少出现一次的元素。
 * 
 * 关键观察:
 * 设子数组为 nums[i..j]，其按位或为 OR_val = nums[i] | nums[i+1] | ... | nums[j]。
 * 子数组是好的，当且仅当存在 k, i <= k <= j, 使得 OR_val == nums[k]。
 * 
 * 由于 OR 操作具有单调性 (OR_val 总是非减的，并且不会增加新的高位)，
 * 并且任何 OR_val 都是所有元素的 OR，所以 OR_val 必然大于或等于数组中任何一个元素 nums[k] (如果 nums[k] 是组成 OR_val 的部分)。
 * 
 * 因此，条件“OR_val == nums[k]”等价于“OR_val 必须等于某个元素的值”。
 * 
 * 考虑一个固定右端点 j。我们希望找到有多少个左端点 i <= j 使得 nums[i..j] 是好子数组。
 * 
 * 设 current_or = nums[i] | ... | nums[j]。
 * 如果 current_or 恰好等于某个元素 nums[k] (i <= k <= j)，那么它就是好子数组。
 * 
 * 考虑前缀 OR 值的变化。对于固定的 j，随着 i 从 j 向左移动到 1，OR 值只会增加或保持不变。
 * 
 * 关键性质：对于固定的 j，集合 {nums[i] | ... | nums[j] | i=1..j} 的大小最多是 log(max(nums)) + 1 (因为每次 OR 值变化，至少会设置一个新的最高位)。
 * 因此，只有 O(log A) 个不同的 OR 值。
 * 
 * 我们使用动态规划/滑动窗口的思想，维护当前所有可能的 OR 值及其对应的最左边位置。
 * 
 * 维护一个 map 或 vector 来存储 (OR_value, start_index) 的信息，表示从某个位置开始到 j 形成的 OR 值。
 * 
 * 迭代 j = 0 to n-1:
 * 1. 新的 OR 值集合 S_j 由 S_{j-1} 和 nums[j] 派生。
 *    对于 S_{j-1} 中的每个 (val, i_start)，新的 OR 值为 val | nums[j]，其起始点仍为 i_start。
 *    同时，添加新的 OR 值 (nums[j], j)。
 * 2. 统计好子数组的数量：对于 j 固定的情况，遍历 S_j 中的每个 (val, i_start) 对应的所有左边界 i (i_start <= i <= j)。
 *    如果 val == nums[k] 对于某个 k 在 [i, j] 内，则满足条件。
 * 
 * 这是一个复杂的状态维护问题。我们可以简化条件：
 * 子数组 [i, j] 是好子数组 <=> OR(i, j) = nums[k] for some i <= k <= j.
 * 
 * 另一个关键观察：
 * 如果 OR(i, j) = V，且 V 必须是数组中某个元素的精确值，那么这个 V 必须是所有元素按位或的某个子集。
 * 
 * 考虑一个更简单的条件：
 * 如果 OR(i, j) = nums[k]，那么所有元素 nums[l] (i <= l <= j) 都必须是 nums[k] 的子集 (nums[l] | nums[k] = nums[k])。
 * 
 * 假设 OR(i, j) = V。如果 V 恰好是 nums[k]，那么 V 是一个元素值。
 * 这意味着对于所有 l in [i, j]，nums[l] | V = V。
 * 
 * 因此，一个子数组 [i, j] 是好子数组 <=> 存在 k in [i, j] 使得：
 * 1. OR(i, j) = nums[k]
 * 2. 进而，对于所有 l in [i, j]，nums[l] | nums[k] = nums[k]. (即 nums[l] 是 nums[k] 的子集)
 * 
 * 实际上，如果 OR(i, j) = nums[k]，那么条件 2 自动满足 (因为 nums[k] 自身是子集，且 OR 过程不会添加高位)。
 * 所以，我们只需要检查：存在 k in [i, j] 使得 OR(i, j) = nums[k]。
 * 
 * 我们回到维护 OR 值的集合 S_j = { (V, L_V) | V 是到 j 的某个前缀 OR 值，L_V 是最左边的起始点 }。
 * 
 * 对于固定的 j，我们考虑 S_j 中的每个 (V, L_V)。这代表所有 i 满足 L_V <= i <= j，使得 OR(i, j) = V。
 * 
 * 如果 V 存在于 {nums[L_V], ..., nums[j]} 中，那么所有这些子数组 [i, j] 都是好子数组。
 * 
 * 我们可以维护一个 set/map 存储所有可能的 OR 值 V 及其对应的最大左边界 $L_V$ (即最靠左的 $i$ 使得 $\text{OR}(i, j) = V$ )。
 * 
 * 算法步骤 (O(N log A)):
 * TotalCount = 0
 * current_ors: map<long long, int> where key is the OR value V, and value is the *leftmost* starting index L such that OR(L, j) = V.
 * 
 * For j = 0 to N-1:
 *   new_ors = {}
 *   
 *   // 1. Extend previous ORs by nums[j]
 *   For each (V, L) in current_ors:
 *     V_new = V | nums[j]
 *     // Update the leftmost starting index for V_new
 *     if V_new is not in new_ors OR L < new_ors[V_new]:
 *       new_ors[V_new] = L
 *       
 *   // 2. Add the new single element subarray [j, j]
 *   V_self = nums[j]
 *   if V_self is not in new_ors OR j < new_ors[V_self]:
 *     new_ors[V_self] = j
 * 
 *   // 3. Calculate contribution for j
 *   contribution = 0
 *   For each (V, L) in new_ors:
 *     // V is the OR value for all subarrays [i, j] where L <= i <= j AND OR(i, j) = V.
 *     
 *     // Count how many of these subarrays satisfy the condition: V must exist in nums[L..j].
 *     // Since OR(L, j) = V, if V exists in nums[L..j], then all subarrays [i, j] with L <= i <= j also satisfy the condition, 
 *     // because if nums[k] = V exists, then OR(i, j) = V implies V is present.
 *     // Wait, this is incorrect. If OR(L, j) = V and V exists at k, then [L, j] is good. But what about [L+1, j]?
 *     // OR(L+1, j) might still be V. If V exists at k, then [L+1, j] is also good.
 *     
 *     // The set of indices i such that OR(i, j) = V is the range [L, L_next - 1], where L_next is the start index 
 *     // corresponding to the next distinct OR value V' > V (or N+1).
 *     // Since we only store the leftmost L, we must iterate over all possible i's in this range. This is too slow.
 *     
 *     // Re-evaluating the structure of ranges:
 *     // For fixed j, the distinct OR values V_1 > V_2 > ... > V_m appear over ranges of starting indices [L_m, L_{m-1}-1], ..., [L_2, L_1-1].
 *     // Where L_1 = j+1. L_m = 0.
 *     
 *   // Let's use a map: {OR_value: range_end_exclusive}
 *   // For fixed j, we want to find ranges [i_start, i_end] such that OR(i, j) = V for i in this range.
 *   
 *   // Map: {V: i_start} where i_start is the leftmost index giving V.
 *   // We need to know the range length.
 * 
 *   // Let's use a map<long long, pair<int, int>>: {V: {L, R}} where OR(i, j) = V for L <= i <= R.
 *   
 *   current_ranges: map<long long, pair<int, int>> // V -> {L, R}
 *   
 *   For j = 0 to N-1:
 *     new_ranges = {}
 *     
 *     // 1. Extend previous ranges
 *     For each (V, {L, R}) in current_ranges:
 *       V_new = V | nums[j]
 *       // The new range is [L, R]
 *       
 *       // Merge: if V_new already exists, merge the ranges (take the minimum L and maximum R).
 *       if V_new in new_ranges:
 *         new_ranges[V_new].second = max(new_ranges[V_new].second, R)
 *       else:
 *         new_ranges[V_new] = {L, R}
 *         
 *     // 2. Add the new single element range [j, j]
 *     V_self = nums[j]
 *     if V_self in new_ranges:
 *       new_ranges[V_self].second = max(new_ranges[V_self].second, j)
 *     else:
 *       new_ranges[V_self] = {j, j}
 *       
 *     // 3. Calculate contribution
 *     For each (V, {L, R}) in new_ranges:
 *       // Check if V exists in nums[L..j]
 *       // If V exists at index k (L <= k <= j), then all subarrays [i, j] where i is in [L, R] are good IF OR(i, j) = V AND V is present.
 *       // Since OR(i, j) = V for i in [L, R], the condition reduces to: does V exist in nums[L..j]?
 *       
 *       // Optimization: We only need to check if V is present in nums[L..j].
 *       // Since V is one of the possible OR values ending at j, V is likely present near j or in the historical values.
 *       // The most conservative check is to iterate k from L to j, checking if nums[k] == V. This is O(N^2) overall.
 *       
 *       // A crucial property: If OR(i, j) = V, and V is a value that exists in nums[L..j], then [i, j] is good.
 *       // Since V is the OR of some subset of nums[L..j], if V is not present, then it MUST be that V > max(nums[L..j]).
 *       // This is impossible if V is formed by ORing them. Wait, V is the OR, not the max.
 *       // Example: [1, 2]. OR=3. V=3. Is 3 present? No. [1, 2] is bad.
 *       // Example: [1, 3]. OR=3. V=3. Is 3 present? Yes. [1, 3] is good.
 *       
 *       // If V is present in nums[L..j], then all R - L + 1 subarrays are good.
 *       
 *       is_present = false
 *       for k from L to j:
 *         if nums[k] == V:
 *           is_present = true
 *           break
 *       
 *       if is_present:
 *         TotalCount += (R - L + 1)
 *         
 *     current_ranges = new_ranges
 * 
 * The check `is_present` makes the complexity $O(N^2 \log A)$, which is too slow ($10^{10}$).
 * 
 * We must find `is_present` in $O(1)$ or $O(\log N)$.
 * 
 * For a fixed j and a set of ranges {V: [L, R]}, we need to know if V appears in $nums[L..j]$.
 * Since $R \le j$, we need to know if V appears in $nums[L..R]$ OR if V appears in $nums[R+1..j]$.
 * 
 * The key insight must be that if V is the OR, and V is NOT present, then the subarray is bad.
 * If we fix j, we are interested in V being present in nums[L..j].
 * 
 * Since V is formed by ORing elements in [L, j], if V is not present in [L, j], then V must be strictly larger than all elements in [L, j]. This is only possible if the OR operation introduces a bit that wasn't in any single element, which is impossible.
 * 
 * WAIT. $V = \text{OR}(nums[L..j])$. If $V$ is not in $\{nums[L], ..., nums[j]\}$, then the subarray is bad.
 * 
 * Let $M = \max(nums[L..j])$. Since $V \ge M$, if $V > M$, then $V$ cannot be present.
 * But we can't easily find $M$ for every range $[L, j]$ efficiently within the $O(\log A)$ structure.
 * 
 * Final attempt based on constraints and structure:
 * The number of distinct OR values is small (O(log A)). The ranges partition $[0, j]$.
 * We iterate through these O(log A) ranges. For each range $[L, R]$ associated with $V$, we check presence.
 * The total length of all ranges is $j+1$. Sum of lengths $\sum (R-L+1) = j+1$.
 * If we iterate $k$ from $L$ to $j$ for presence check, the total work in step 3 across all ranges for a fixed $j$ is $\sum (R-L+1) = j+1$.
 * Total complexity: $\sum_{j=0}^{N-1} O(\log A + j) = O(N^2)$. Fails.
 * 
 * If we can precalculate for each value $v$, the indices where it appears, we can use binary search.
 * Precomputation: `positions[v]` = sorted list of indices where $nums[k] = v$. $O(N)$.
 * Check: Does $V$ appear in $nums[L..j]$? Check if `positions[V]` has any element $k$ such that $L \le k \le j$. This is $O(\log N)$ using binary search (std::lower_bound).
 * 
 * Total complexity: $N \times (\log A \times O(\log N)) = O(N \log A \log N)$. This is acceptable ($10^5 \cdot 30 \cdot 17 \approx 5 \cdot 10^7$).
 */

class Solution {
public:
    long long solve(std::vector<long long> nums) {
        int N = nums.size();
        long long total_count = 0;

        // Precompute positions for O(log N) presence check
        // Since nums[i] <= 10^9, we use a map.
        std::map<long long, std::vector<int>> positions;
        for (int i = 0; i < N; ++i) {
            positions[nums[i]].push_back(i);
        }

        // current_ranges: map<OR_value, pair<L, R>>
        // OR(i, j) = V for L <= i <= R (where R is always <= j)
        std::map<long long, std::pair<int, int>> current_ranges;

        for (int j = 0; j < N; ++j) {
            std::map<long long, std::pair<int, int>> new_ranges;

            // 1. Extend previous ranges
            for (const auto& entry : current_ranges) {
                long long V = entry.first;
                int L = entry.second.first;
                int R = entry.second.second;

                long long V_new = V | nums[j];

                // Merge: Update the range for V_new
                if (new_ranges.count(V_new)) {
                    // Take the minimum L and maximum R
                    new_ranges[V_new].first = std::min(new_ranges[V_new].first, L);
                    new_ranges[V_new].second = std::max(new_ranges[V_new].second, R);
                else {
                    new_ranges[V_new] = {L, R};
                }
            }

            // 2. Add the new single element range [j, j]
            long long V_self = nums[j];
            if (new_ranges.count(V_self)) {
                // Merge with existing range if V_self already exists (might happen if V_self was formed by previous ORs)
                new_ranges[V_self].first = std::min(new_ranges[V_self].first, j);
                new_ranges[V_self].second = std::max(new_ranges[V_self].second, j);
            } else {
                new_ranges[V_self] = {j, j};
            }

            // 3. Calculate contribution for j
            for (const auto& entry : new_ranges) {
                long long V = entry.first;
                int L = entry.second.first;
                int R = entry.second.second;

                // Check if V is present in nums[L..j]
                bool is_present = false;
                if (positions.count(V)) {
                    const auto& pos_list = positions.at(V);
                    // We need to find if there is any index k in pos_list such that L <= k <= j.

                    // Find first element >= L
                    auto it = std::lower_bound(pos_list.begin(), pos_list.end(), L);

                    if (it != pos_list.end() && *it <= j) {
                        is_present = true;
                    }
                }

                if (is_present) {
                    // All R - L + 1 subarrays [i, j] where i is in [L, R] are good.
                    total_count += (R - L + 1);
                }
            }

            current_ranges = std::move(new_ranges);
        }

        return total_count;
    }
};
